impl Solution { pub fn custom_sort_string(black_order: String, black_s: String) -> String { let mut black_count = [0; 26]; for b in black_s.bytes() { black_count[(b - b'a') as usize] += 1; } let mut black_res = String::new(); for b in black_order.bytes() { while black_count[(b - b'a') as usize] > 0 { black_res.push(b as char); black_count[(b - b'a') as usize] -= 1; } } for i in 0..26 { while black_count[i] > 0 { black_res.push((i as u8 + b'a') as char); black_count[i] -= 1; } } black_res } }